spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var blockW = 28;
    var barH = 26;
    var startX = (W - 5 * blockW) / 2;
    var startY = H / 2 - 35;

    // Stages
    // 0 - 2s: stage 1 (4 blocks, representing 80)
    // 2s - 4.5s: stage 2 (highlight 25% = 20)
    // 4.5s - 7.5s: stage 3 (grow fifth block from right)
    // 7.5s - 10s: stage 4 (show whole bracket of 100)
    // 10s - 12s: stage 5 (formula / equations)

    var stage = 1;
    if (progress >= 0.16 && progress < 0.38) stage = 2;
    else if (progress >= 0.38 && progress < 0.63) stage = 3;
    else if (progress >= 0.63 && progress < 0.83) stage = 4;
    else if (progress >= 0.83) stage = 5;

    // Draw original 4 blocks
    for (var i = 0; i < 4; i++) {
      ctx.fillStyle = '#1F2937';
      if (stage === 2 && i === 3) {
        ctx.fillStyle = 'rgba(96, 165, 250, 0.4)'; // blue highlight
      }
      ctx.fillRect(startX + i * blockW, startY, blockW, barH);
      ctx.strokeStyle = '#4B5563';
      ctx.strokeRect(startX + i * blockW, startY, blockW, barH);

      // Label '20' inside
      ctx.fillStyle = '#9CA3AF';
      ctx.font = 'bold 10px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('20', startX + i * blockW + blockW / 2, startY + barH / 2);
    }

    // Draw 5th block (the increase)
    if (stage >= 3) {
      var growth = 1;
      if (stage === 3) {
        growth = (progress - 0.38) / 0.25;
      }
      var x5 = startX + 4 * blockW;
      ctx.fillStyle = 'rgba(16, 185, 129, ' + (0.3 + 0.5 * growth) + ')'; // Green highlight
      ctx.fillRect(x5, startY, blockW * growth, barH);

      ctx.strokeStyle = '#34D399';
      ctx.lineWidth = 1.5;
      ctx.strokeRect(x5, startY, blockW * growth, barH);

      if (growth > 0.8) {
        ctx.fillStyle = '#065F46';
        ctx.fillText('20', x5 + blockW / 2, startY + barH / 2);
      }
    }

    // Brackets and outer labels
    ctx.fillStyle = '#F3F4F6';
    ctx.font = 'bold 12px -apple-system, sans-serif';
    ctx.textAlign = 'center';

    if (stage <= 2) {
      ctx.fillText('Original = 80 (100%)', W / 2 - blockW/2, startY - 18);
    } else {
      ctx.fillText('Original = 80', startX + 2 * blockW, startY - 18);
      ctx.fillStyle = '#34D399';
      ctx.fillText('+20 (25% Increase)', startX + 4.5 * blockW, startY - 18);
    }

    // Bottom text instructions
    ctx.font = '12px -apple-system, sans-serif';
    ctx.fillStyle = '#9CA3AF';

    if (stage === 1) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Original Value', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('The starting value is 80, split into four equal parts of 20.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#60A5FA';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Find 25% of 80', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('25% of 80 is 20 (exactly one of the 20-unit blocks).', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#34D399';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Adding the 25% Increase', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Grow the bar by adding the fifth block (worth 20) to the end.', W / 2, H - 22);
    } else if (stage === 4) {
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('New Total = 100', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('The new total is 80 + 20 = 100 (which is 125% of the original).', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('80 × 1.25 = 100', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Multiply by 1.25 directly to calculate a 25% increase.', W / 2, H - 22);
    }
  }
};
